// src/app/services/preferences.service.ts
import { Injectable, inject, signal, computed } from '@angular/core';
import { CustomService, MPageService } from '@clinicaloffice/mpage-developer';
import { SchedulePreferences, DEFAULT_PREFERENCES } from '../models/schedule.model';

const DMINFO_DOMAIN = 'ONC_SCHED';
const DMINFO_NAME = 'USER_PREFS';
const LS_KEY_PREFIX = 'onc_sched_prefs_';

@Injectable({ providedIn: 'root' })
export class PreferencesService {
  private readonly customService = inject(CustomService);
  private readonly mPage = inject(MPageService);

  private readonly _preferences = signal<SchedulePreferences>({ ...DEFAULT_PREFERENCES });
  private readonly _loaded = signal(false);
  private prsnlId = 0;

  readonly preferences = this._preferences.asReadonly();
  readonly loaded = this._loaded.asReadonly();
  readonly selectedPhysicianId = computed(() => this._preferences().physician_id);
  readonly sortColumn = computed(() => this._preferences().sort_column);
  readonly sortDirection = computed(() => this._preferences().sort_direction);
  readonly columnOrder = computed(() => this._preferences().column_order);
  readonly columnVisibility = computed(() => this._preferences().column_visibility);

  loadPreferences(prsnlId: number): void {
    this.prsnlId = prsnlId;

    // Fast path: localStorage cache
    try {
      const cached = localStorage.getItem(LS_KEY_PREFIX + prsnlId);
      if (cached) {
        const parsed = JSON.parse(cached) as SchedulePreferences;
        this._preferences.set({ ...DEFAULT_PREFERENCES, ...parsed });
      }
    } catch {
      // localStorage unavailable or corrupt — continue
    }

    // Authoritative: DMInfo
    const dmInfo = this.customService.emptyDmInfo;
    dmInfo.infoDomain = DMINFO_DOMAIN;
    dmInfo.infoName = DMINFO_NAME;
    dmInfo.infoDomainId = prsnlId;

    this.customService.executeDmInfoAction('loadUserPrefs', 'r', [dmInfo], () => {
      try {
        const result = this.customService.get('loadUserPrefs');
        if (result?.infoLongText) {
          const prefs = JSON.parse(result.infoLongText) as SchedulePreferences;
          this._preferences.set({ ...DEFAULT_PREFERENCES, ...prefs });
          this.updateLocalStorage();
        }
      } catch {
        this.mPage.putLog('Failed to parse user preferences');
      }
      this._loaded.set(true);
    });
  }

  setPhysicianFilter(physicianId: number | null): void {
    this._preferences.update(p => ({ ...p, physician_id: physicianId }));
    this.savePreferences();
  }

  setSortColumn(column: string | null, direction: 'asc' | 'desc' | null): void {
    this._preferences.update(p => ({ ...p, sort_column: column, sort_direction: direction }));
    this.savePreferences();
  }

  setColumnOrder(columns: string[]): void {
    this._preferences.update(p => ({ ...p, column_order: columns }));
    this.savePreferences();
  }

  private savePreferences(): void {
    this.updateLocalStorage();

    const dmInfo = this.customService.emptyDmInfo;
    dmInfo.infoDomain = DMINFO_DOMAIN;
    dmInfo.infoName = DMINFO_NAME;
    dmInfo.infoDomainId = this.prsnlId;
    dmInfo.infoLongText = JSON.stringify(this._preferences());

    this.customService.executeDmInfoAction('saveUserPrefs', 'w', [dmInfo], () => {
      this.mPage.putLog('User preferences saved');
    });
  }

  private updateLocalStorage(): void {
    try {
      localStorage.setItem(LS_KEY_PREFIX + this.prsnlId, JSON.stringify(this._preferences()));
    } catch {
      // localStorage unavailable — skip
    }
  }
}
